import hashlib
import json
import math
import re
import time
from dataclasses import dataclass, field
from typing import Any


# ── Prompt template with variable validation ─────────────────────────────────
@dataclass
class PromptTemplate:
    name: str
    version: str  # semver: '1.2.3'
    template: str  # uses {variable} placeholders
    variables: list[str]  # required variable names
    description: str = ''
    author: str = ''
    created_at: float = field(default_factory=time.time)

    def render(self, **kwargs) -> str:
        missing = [v for v in self.variables if v not in kwargs]
        if missing:
            raise ValueError(f'Missing variables: {missing}')
        extra = [k for k in kwargs if k not in self.variables]
        if extra:
            raise ValueError(f'Unexpected variables: {extra}')
        return self.template.format(**kwargs)

    def _parse_variables(self) -> list[str]:
        return re.findall(r'\{(\w+)\}', self.template)


# ── Prompt registry ───────────────────────────────────────────────────────────
class PromptRegistry:
    """
    In-memory registry; in production, back with Redis or a DB.
    Tracks production alias and version history.
    """

    def __init__(self):
        self._store: dict[str, dict[str, PromptTemplate]] = {}  # name → version → template
        self._production: dict[str, str] = {}  # name → version
        self._history: dict[str, list[str]] = {}  # name → ordered versions

    def register(self, prompt: PromptTemplate) -> None:
        self._store.setdefault(prompt.name, {})
        self._store[prompt.name][prompt.version] = prompt
        self._history.setdefault(prompt.name, [])
        if prompt.version not in self._history[prompt.name]:
            self._history[prompt.name].append(prompt.version)
        # First registration auto-promotes to production
        if prompt.name not in self._production:
            self._production[prompt.name] = prompt.version

    def get(self, name: str, version: str = 'production') -> PromptTemplate:
        if version == 'production':
            version = self._production.get(name, 'latest')
        if version == 'latest':
            versions = self._history.get(name, [])
            if not versions:
                raise KeyError(f'No versions for prompt: {name}')
            version = versions[-1]
        try:
            return self._store[name][version]
        except KeyError:
            raise KeyError(f'Prompt not found: {name}@{version}')

    def promote(self, name: str, version: str) -> None:
        """Set version as production."""
        if name not in self._store or version not in self._store[name]:
            raise KeyError(f'Cannot promote unknown prompt: {name}@{version}')
        self._production[name] = version

    def rollback(self, name: str) -> str:
        """Roll back to previous production version."""
        history = self._history.get(name, [])
        current = self._production.get(name)
        if current not in history or history.index(current) == 0:
            raise ValueError(f'No previous version to roll back to for {name}')
        prev_idx = history.index(current) - 1
        prev_version = history[prev_idx]
        self._production[name] = prev_version
        return prev_version

    def list_versions(self, name: str) -> list[str]:
        return self._history.get(name, [])


# ── A/B experiment router ─────────────────────────────────────────────────────
@dataclass
class Experiment:
    experiment_id: str
    prompt_name: str
    control_version: str   # bucket 0..49
    treatment_version: str # bucket 50..99
    traffic_pct: float = 50.0  # % of users in experiment


class ABRouter:
    """
    Deterministically routes user to control or treatment.
    Bucket = hash(user_id + experiment_id) % 100.
    """

    def __init__(self, registry: PromptRegistry):
        self._registry = registry
        self._experiments: dict[str, Experiment] = {}
        self._results: dict[str, dict[str, list[float]]] = {}  # exp_id → bucket → metrics

    def add_experiment(self, exp: Experiment) -> None:
        self._experiments[exp.experiment_id] = exp
        self._results[exp.experiment_id] = {'control': [], 'treatment': []}

    def route(self, experiment_id: str, user_id: str) -> tuple[str, PromptTemplate]:
        """Returns (bucket_name, prompt_template)."""
        exp = self._experiments[experiment_id]
        bucket = self._bucket(user_id, experiment_id)
        if bucket < exp.traffic_pct:
            if bucket < exp.traffic_pct / 2:
                return 'control', self._registry.get(exp.prompt_name, exp.control_version)
            else:
                return 'treatment', self._registry.get(exp.prompt_name, exp.treatment_version)
        # Outside experiment — serve production
        return 'production', self._registry.get(exp.prompt_name)

    def record(self, experiment_id: str, bucket: str, metric: float) -> None:
        self._results[experiment_id][bucket].append(metric)

    def analyse(self, experiment_id: str) -> dict:
        data = self._results[experiment_id]
        control = data['control']
        treatment = data['treatment']
        if len(control) < 30 or len(treatment) < 30:
            return {'status': 'insufficient_data', 'n_control': len(control), 'n_treatment': len(treatment)}

        mean_c = sum(control) / len(control)
        mean_t = sum(treatment) / len(treatment)
        lift = (mean_t - mean_c) / mean_c if mean_c else 0.0

        # Two-sample z-test (continuous metric)
        var_c = sum((x - mean_c) ** 2 for x in control) / len(control)
        var_t = sum((x - mean_t) ** 2 for x in treatment) / len(treatment)
        se = math.sqrt(var_c / len(control) + var_t / len(treatment))
        z = (mean_t - mean_c) / se if se else 0.0
        # p < 0.05 ↔ |z| > 1.96
        significant = abs(z) > 1.96

        return {
            'status': 'complete',
            'mean_control': round(mean_c, 4),
            'mean_treatment': round(mean_t, 4),
            'lift': round(lift, 4),
            'z_score': round(z, 3),
            'significant': significant,
            'winner': 'treatment' if significant and lift > 0 else ('control' if significant else 'no_winner'),
        }

    @staticmethod
    def _bucket(user_id: str, experiment_id: str) -> int:
        h = hashlib.md5(f'{user_id}:{experiment_id}'.encode()).hexdigest()
        return int(h[:8], 16) % 100


# ── Prompt regression runner ──────────────────────────────────────────────────
@dataclass
class GoldenCase:
    input_vars: dict[str, Any]
    required_keywords: list[str]  # all must appear in output
    forbidden_keywords: list[str] = field(default_factory=list)
    min_length: int = 50


class PromptRegressionRunner:
    """Runs golden cases against a prompt version using a mock LLM."""

    def __init__(self, llm_fn):
        self._llm = llm_fn  # fn(prompt_text) -> str

    def run(self, template: PromptTemplate, cases: list[GoldenCase]) -> dict:
        passed = 0
        failures = []
        for i, case in enumerate(cases):
            prompt_text = template.render(**case.input_vars)
            output = self._llm(prompt_text)
            ok, reason = self._check(output, case)
            if ok:
                passed += 1
            else:
                failures.append({'case': i, 'reason': reason, 'output_snippet': output[:100]})

        regression_rate = (len(cases) - passed) / len(cases) if cases else 0.0
        return {
            'version': template.version,
            'total': len(cases),
            'passed': passed,
            'failed': len(failures),
            'regression_rate': round(regression_rate, 3),
            'deployable': regression_rate <= 0.05,  # gate: max 5% failures
            'failures': failures,
        }

    @staticmethod
    def _check(output: str, case: GoldenCase) -> tuple[bool, str]:
        lower = output.lower()
        for kw in case.required_keywords:
            if kw.lower() not in lower:
                return False, f'Missing required keyword: {kw}'
        for kw in case.forbidden_keywords:
            if kw.lower() in lower:
                return False, f'Forbidden keyword present: {kw}'
        if len(output) < case.min_length:
            return False, f'Output too short: {len(output)} < {case.min_length}'
        return True, 'ok'


# ── Demo ──────────────────────────────────────────────────────────────────────
if __name__ == '__main__':
    registry = PromptRegistry()

    v1 = PromptTemplate(
        name='summariser',
        version='1.0.0',
        template='Summarise this text in {style} style:\n\n{text}',
        variables=['style', 'text'],
        description='Basic summariser',
        author='alice',
    )
    v2 = PromptTemplate(
        name='summariser',
        version='1.1.0',
        template=('You are an expert editor. Summarise the following text in a {style} style.'
                  ' Be concise and capture key points.\n\nText: {text}\n\nSummary:'),
        variables=['style', 'text'],
        description='Improved summariser with persona',
        author='alice',
    )

    registry.register(v1)
    registry.register(v2)
    print('Production version:', registry.get('summariser', 'production').version)  # 1.0.0

    # Regression test v2 before promoting
    cases = [
        GoldenCase(
            input_vars={'style': 'bullet points', 'text': 'The sky is blue because of Rayleigh scattering.'},
            required_keywords=['rayleigh', 'scatter'],
            min_length=30,
        ),
    ]

    def mock_llm(prompt: str) -> str:
        return 'The sky appears blue due to Rayleigh scattering of sunlight by atmospheric particles.'

    runner = PromptRegressionRunner(mock_llm)
    result = runner.run(v2, cases)
    print('Regression result:', result)

    if result['deployable']:
        registry.promote('summariser', '1.1.0')
        print('Promoted to production:', registry.get('summariser', 'production').version)

    # Rollback demo
    prev = registry.rollback('summariser')
    print('Rolled back to:', prev)
